sys_ui_script.script:
/**
 * Global UI Script
 * Function: NowAssistPanelMessageAutoExpand()
 *
 * What it does (continuously):
 * - Watches the Now Assist panel DOM (incl. OPEN shadow roots)
 * - Forces all message rich-text blocks to be expanded (display:flex etc.)
 * - Hides "Show more" / "Show less" controls
 *
 * It installs ONCE in window.top (the shell) and keeps enforcing for new messages.
 */
function NowAssistPanelMessageAutoExpand(options) {
  // ---- pick shell window (Now Assist lives above gsft_main iframe) ----
  var shellWin = window;
  try {
    if (window.top && window.top.document) shellWin = window.top;
  } catch (e) {
    shellWin = window;
  }

  // Reuse existing controller if already installed
  if (shellWin.__nowAssistAutoExpandV4) {
    shellWin.__nowAssistAutoExpandV4.start();
    return shellWin.__nowAssistAutoExpandV4;
  }

  // ---- config ----
  options = options || {};
  var CFG = {
    intervalMs: typeof options.intervalMs === "number" ? options.intervalMs : 300,       // periodic enforcement (fallback)
    rootRefreshMs: typeof options.rootRefreshMs === "number" ? options.rootRefreshMs : 1500, // re-discover panel roots
    debug: !!options.debug
  };

  // ---- controller state ----
  var state = {
    running: false,
    intervalId: null,
    tickScheduled: false,
    lastRootRefresh: 0,
    searchRoots: [],

    // observer bookkeeping (ES5-friendly)
    observedTargets: [],
    observers: []
  };

  function isObserved(target) {
    for (var i = 0; i < state.observedTargets.length; i++) {
      if (state.observedTargets[i] === target) return true;
    }
    return false;
  }

  function observe(target) {
    if (!target || isObserved(target) || !shellWin.MutationObserver) return;

    try {
      var mo = new shellWin.MutationObserver(function () {
        // DOM changed (new messages, re-render, style updates) -> re-apply soon
        scheduleTick();
      });

      mo.observe(target, { childList: true, subtree: true, attributes: true });
      state.observedTargets.push(target);
      state.observers.push(mo);
    } catch (e) {
      // ignore
    }
  }

  // ---- style injection (helps even when components re-apply non-important inline styles) ----
  function ensureStyleInjected(doc) {
    try {
      if (!doc || !doc.head) return;
      if (doc.getElementById("nowassist-autoexpand-style")) return;

      var style = doc.createElement("style");
      style.id = "nowassist-autoexpand-style";
      style.type = "text/css";
      style.appendChild(
        doc.createTextNode(
          ".nowassist-autoexpanded{display:flex !important;max-height:none !important;height:auto !important;overflow:visible !important;-webkit-line-clamp:unset !important;}" +
          ".nowassist-hide-toggle{display:none !important;}"
        )
      );
      doc.head.appendChild(style);
    } catch (e) {}
  }

  // ---- same-origin iframe docs (sometimes shell UI uses additional iframes) ----
  function collectDocuments(doc) {
    var docs = [];
    if (!doc) return docs;

    docs.push(doc);

    var iframes = [];
    try { iframes = doc.querySelectorAll("iframe"); } catch (e) { iframes = []; }

    for (var i = 0; i < iframes.length; i++) {
      try {
        var d = iframes[i].contentWindow && iframes[i].contentWindow.document;
        if (d) docs.push(d);
      } catch (e2) {
        // cross-origin -> ignore
      }
    }
    return docs;
  }

  // ---- deep query through OPEN shadow roots (bounded by starting root) ----
  function deepQueryAll(root, selector) {
    var results = [];
    if (!root) return results;

    var queue = [root];
    var seen = [];

    function seenRoot(r) {
      for (var i = 0; i < seen.length; i++) if (seen[i] === r) return true;
      return false;
    }

    while (queue.length) {
      var r = queue.shift();
      if (!r || seenRoot(r)) continue;
      seen.push(r);

      // collect matches
      try {
        var found = r.querySelectorAll(selector);
        for (var f = 0; f < found.length; f++) results.push(found[f]);
      } catch (e) {}

      // traverse elements to enter OPEN shadow roots
      var els = [];
      try { els = r.querySelectorAll("*"); } catch (e2) { els = []; }

      for (var j = 0; j < els.length; j++) {
        var el = els[j];
        if (el && el.shadowRoot) queue.push(el.shadowRoot);
      }
    }

    return results;
  }

  // ---- locate the panel roots to scan/observe (refreshed periodically) ----
  function refreshRoots(force) {
    var now = GetTimeNow();
    if (!force && (now - state.lastRootRefresh) < CFG.rootRefreshMs) return;

    state.lastRootRefresh = now;
    state.searchRoots = [];

    var docs = collectDocuments(shellWin.document);

    for (var d = 0; d < docs.length; d++) {
      var doc = docs[d];
      ensureStyleInjected(doc);

      // Fast paths (prefer these)
      var direct = null;
      try {
        direct = doc.querySelector(
          "sn-cs-control-chat, sn-cs-control-chat-container, sn-now-assist, sn-now-assist-panel, sn-assist-panel, now-assist, now-assist-panel"
        );
      } catch (e) {
        direct = null;
      }
      if (direct) state.searchRoots.push(direct.shadowRoot || direct);

      // Heuristic fallback: find *one* open shadow root containing our target classes
      if (!state.searchRoots.length) {
        var all = [];
        try { all = doc.querySelectorAll("*"); } catch (e2) { all = []; }

        for (var i = 0; i < all.length && i < 5000; i++) {
          var el = all[i];
          if (!el || !el.shadowRoot) continue;
          try {
            if (
              el.shadowRoot.querySelector(".sn-cs-rich-text-height-wrapper") ||
              el.shadowRoot.querySelector(".sn-cs-rich-text-container") ||
              el.shadowRoot.querySelector(".now-button-bar-label")
            ) {
              state.searchRoots.push(el.shadowRoot);
              break;
            }
          } catch (e3) {}
        }
      }

      // Observe document to detect panel open/close / rerenders
      observe(doc.documentElement || doc.body);
    }

    // Worst-case fallback
    if (!state.searchRoots.length) state.searchRoots = [shellWin.document];

  }

  // ---- apply expansion + hide toggles ----
  function forceExpand(el) {
    if (!el) return;
    try { el.classList.add("nowassist-autoexpanded"); } catch (e) {}

    // Keep inline !important too (belt + suspenders)
    if (el.style && el.style.setProperty) {
      try {
        el.style.setProperty("display", "flex", "important");
        el.style.setProperty("max-height", "none", "important");
        el.style.setProperty("height", "auto", "important");
        el.style.setProperty("overflow", "visible", "important");
        el.style.setProperty("-webkit-line-clamp", "unset", "important");
      } catch (e2) {}
    }
  }

  function hideShowToggle(labelEl) {
    if (!labelEl) return;

    var text = "";
    try { text = (labelEl.textContent || "").replace(/\s+/g, " ").trim().toLowerCase(); } catch (e) {}

    if (text !== "show more" && text !== "show less") return;

    var container = null;
    try {
      if (labelEl.closest) {
        container = labelEl.closest("now-button-bar") ||
                    labelEl.closest("button") ||
                    labelEl.closest(".now-button-bar");
      }
    } catch (e2) {}

    if (!container) container = labelEl.parentNode;

    if (container && container.classList) {
      try { container.classList.add("nowassist-hide-toggle"); } catch (e3) {}
    }
    if (container && container.style && container.style.setProperty) {
      try { container.style.setProperty("display", "none", "important"); } catch (e4) {}
    }
  }

  function enforceInRoot(root) {
    // Expand wrappers + containers (both appear in your DOM screenshots)
    var expandTargets = deepQueryAll(
      root,
      ".sn-cs-rich-text-height-wrapper.truncateable.expandable, .sn-cs-rich-text-container"
    );
    for (var i = 0; i < expandTargets.length; i++) forceExpand(expandTargets[i]);

    // Hide Show more/less
    var labels = deepQueryAll(root, ".now-button-bar-label");
    for (var j = 0; j < labels.length; j++) hideShowToggle(labels[j]);

    // Observe relevant OPEN shadow roots so we react instantly to new messages
    // (we discover them by traversing within this root)
    var all = deepQueryAll(root, "*");
    for (var k = 0; k < all.length; k++) {
      var el = all[k];
      if (el && el.shadowRoot) observe(el.shadowRoot);
    }

    // Also observe the root itself if possible
    observe(root);
  }

  // ---- scheduling ----
  function scheduleTick() {
    if (state.tickScheduled) return;
    state.tickScheduled = true;
    shellWin.setTimeout(function () {
      state.tickScheduled = false;
      tick();
    }, 30);
  }

  function tick() {
    refreshRoots(false);
    for (var i = 0; i < state.searchRoots.length; i++) {
      enforceInRoot(state.searchRoots[i]);
    }
  }

  // ---- public controller ----
  var controller = {
    start: function () {
      if (state.running) return;
      state.running = true;

      refreshRoots(true);
      tick();

      // Fallback polling (covers cases where re-renders happen without observable mutations in accessible roots)
      state.intervalId = shellWin.setInterval(function () {
        tick();
      }, CFG.intervalMs);
    },

    stop: function () {
      state.running = false;

      if (state.intervalId) {
        shellWin.clearInterval(state.intervalId);
        state.intervalId = null;
      }

      for (var i = 0; i < state.observers.length; i++) {
        try { state.observers[i].disconnect(); } catch (e) {}
      }
      state.observers = [];
      state.observedTargets = [];
    }
  };

  shellWin.__nowAssistAutoExpandV4 = controller;
  controller.start();
  return controller;
}
